        let (mut asc, mut dsc) = (true, true);
        for i in 1..a.len() {
            if a[i-1] > a[i] { asc = false }
            if a[i-1] < a[i] { dsc = false }
            if !asc && !dsc { break }
        }
        if asc { return }
        if dsc { a.reverse(); return }
    }
    while a.len() > 32 {
        let (m, r) = (a.len()/2, a.len()-1);
        if a[0] > a[m] { a.swap(0, m) }
        if a[0] > a[r] { a.swap(0, r) }
        if a[m] > a[r] { a.swap(m, r) }
        let (p, mut l, mut g, mut i) = (a[m].clone(), 0, a.len(), 0);
        while i < g {
            match a[i].cmp(&p) {
                Ordering::Less => { a.swap(i, l); l += 1; i += 1 }
                Ordering::Greater => {
